//! Human-readable renderer for JSON Schemas generated by `schemars`.
//!
//! This module walks a JSON Schema (represented as a [`serde_json::Value`]) and produces
//! a tree-style terminal output that documents available fields, types, enum variants,
//! and descriptions.

use std::fmt::Write as _;
use std::io::{self, Write};

use colored::Colorize;
use serde_json::Value;

/// Render a JSON Schema as human-readable documentation to `output`.
///
/// The schema should be the root schema object produced by `schemars::generate::schema_for`.
/// It may contain `$defs` for referenced type definitions.
pub fn render(schema: &Value, output: &mut dyn Write) -> io::Result<()> {
    let defs = schema
        .get("$defs")
        .or_else(|| schema.get("definitions"));

    let mut buf = String::new();
    render_node(schema, defs, &mut buf, 0, true);
    write!(output, "{buf}")
}

/// Resolve a dotted field path (e.g. "build.start_point_strategy") into the sub-schema
/// for that field. Returns a self-contained schema [`Value`] that can be passed to [`render`].
///
/// At each path segment, this descends into `properties.<segment>`, resolving any `$ref`
/// along the way.
pub fn resolve_path(schema: &Value, path: &str) -> Option<Value> {
    let defs = schema
        .get("$defs")
        .or_else(|| schema.get("definitions"));

    let mut current = resolve(schema, defs);

    for segment in path.split('.') {
        // Try direct properties lookup.
        if let Some(prop) = current.get("properties").and_then(|p| p.get(segment)) {
            current = resolve(prop, defs);
            continue;
        }

        // If this is a oneOf/anyOf (tagged enum), look through variants for the field.
        let variants = current
            .get("oneOf")
            .or_else(|| current.get("anyOf"))
            .and_then(Value::as_array);

        if let Some(variants) = variants {
            let mut found = false;
            for variant in variants {
                // For $ref + inline properties pattern, check the resolved ref.
                let resolved_variant = resolve(variant, defs);
                if let Some(prop) = resolved_variant.get("properties").and_then(|p| p.get(segment))
                {
                    current = resolve(prop, defs);
                    found = true;
                    break;
                }
            }
            if found {
                continue;
            }
        }

        return None;
    }

    // Return a self-contained schema with $defs included for rendering.
    let mut result = current.clone();
    if let Some(defs) = defs {
        if let Some(obj) = result.as_object_mut() {
            obj.insert("$defs".to_string(), defs.clone());
        }
    }
    Some(result)
}

/// Maximum recursion depth to prevent stack overflow on self-referential schemas.
const MAX_DEPTH: usize = 16;

/// Render a single schema node into the buffer at the given indentation depth.
fn render_node(
    node: &Value,
    defs: Option<&Value>,
    buf: &mut String,
    depth: usize,
    _is_last: bool,
) {
    if depth >= MAX_DEPTH {
        write_indented(buf, depth, &format!("{}", "...".dimmed()));
        return;
    }

    let node = resolve(node, defs);

    // Dispatch based on schema shape.
    if let Some(one_of) = node.get("oneOf").and_then(Value::as_array) {
        render_one_of(one_of, node, defs, buf, depth);
    } else if let Some(any_of) = node.get("anyOf").and_then(Value::as_array) {
        render_any_of(any_of, node, defs, buf, depth);
    } else if let Some(properties) = node.get("properties").and_then(Value::as_object) {
        render_object(properties, node, defs, buf, depth);
    } else if let Some(enum_values) = node.get("enum").and_then(Value::as_array) {
        render_enum(enum_values, buf, depth);
    } else if let Some(items) = node.get("items") {
        render_array(items, node, defs, buf, depth);
    } else {
        // Leaf type (string, integer, number, boolean, null).
        let summary = type_summary(node);
        write_indented(buf, depth, &format!("{}", summary.cyan()));
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Object rendering
// ─────────────────────────────────────────────────────────────────────────────

fn render_object(
    properties: &serde_json::Map<String, Value>,
    parent: &Value,
    defs: Option<&Value>,
    buf: &mut String,
    depth: usize,
) {
    let required = required_fields(parent);

    let entries: Vec<_> = properties.iter().collect();
    for (i, (name, schema)) in entries.iter().enumerate() {
        let is_last = i == entries.len() - 1;
        let connector = if is_last { "└── " } else { "├── " };
        let optional_str = if !required.contains(&name.as_str()) {
            format!(" {}", "(optional)".dimmed())
        } else {
            String::new()
        };

        let resolved = resolve(schema, defs);
        let description = resolved.get("description").and_then(Value::as_str);

        // Determine if this is a complex type that needs sub-rendering.
        let is_complex = resolved.get("properties").is_some()
            || resolved.get("oneOf").is_some()
            || resolved.get("anyOf").is_some();

        if is_complex {
            let type_hint = brief_type_hint(resolved);
            let line = format!(
                "{}{}{}: {}",
                connector.dimmed(),
                name.bold(),
                optional_str,
                type_hint.cyan()
            );
            write_indented(buf, depth, &line);

            if let Some(desc) = description {
                let cont = if is_last { "    " } else { "│   " };
                write_description(buf, depth, cont, desc);
            }

            let child_depth = depth + 1;
            render_node(resolved, defs, buf, child_depth, is_last);
        } else {
            let summary = type_summary(resolved);
            let line = format!(
                "{}{}: {}{}",
                connector.dimmed(),
                name.bold(),
                summary.cyan(),
                optional_str
            );
            write_indented(buf, depth, &line);

            if let Some(desc) = description {
                let cont = if is_last { "    " } else { "│   " };
                write_description(buf, depth, cont, desc);
            }
        }

        // Blank line between properties for readability (except after the last).
        if !is_last {
            write_indented(buf, depth, &format!("{}", "│".dimmed()));
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Enum / union rendering
// ─────────────────────────────────────────────────────────────────────────────

/// Render a simple `"enum": [...]` (string enum with fixed values).
fn render_enum(values: &[Value], buf: &mut String, depth: usize) {
    let formatted: Vec<String> = values
        .iter()
        .map(|v| match v {
            Value::String(s) => format!("{}", format!("\"{s}\"").yellow()),
            Value::Null => format!("{}", "null".yellow()),
            other => format!("{}", other.to_string().yellow()),
        })
        .collect();

    write_indented(
        buf,
        depth,
        &format!("{} {}", "One of:".dimmed(), formatted.join(", ")),
    );
}

/// Render `"oneOf": [...]` — typically a tagged enum.
fn render_one_of(
    variants: &[Value],
    _parent: &Value,
    defs: Option<&Value>,
    buf: &mut String,
    depth: usize,
) {
    render_variants(variants, defs, buf, depth);
}

/// Render `"anyOf": [...]` — typically Option<T> (T + null).
fn render_any_of(
    variants: &[Value],
    _parent: &Value,
    defs: Option<&Value>,
    buf: &mut String,
    depth: usize,
) {
    // schemars represents Option<T> as anyOf: [T_schema, {"type": "null"}].
    // If one variant is just null, present the inner type directly.
    let non_null: Vec<&Value> = variants
        .iter()
        .filter(|v| {
            let resolved = resolve(v, defs);
            resolved.get("type").and_then(Value::as_str) != Some("null")
        })
        .collect();

    let has_null = non_null.len() < variants.len();

    if non_null.len() == 1 && has_null {
        // Simple Option<T> — render the inner type directly.
        let inner = resolve(non_null[0], defs);

        if inner.get("oneOf").is_some()
            || inner.get("anyOf").is_some()
            || inner.get("properties").is_some()
        {
            render_node(inner, defs, buf, depth, true);
        } else {
            let summary = type_summary(inner);
            write_indented(buf, depth, &format!("{}", summary.cyan()));
        }
    } else {
        // General union — render as variants.
        render_variants(variants, defs, buf, depth);
    }
}

/// Render a list of variant schemas (shared by oneOf and anyOf).
fn render_variants(variants: &[Value], defs: Option<&Value>, buf: &mut String, depth: usize) {
    for (i, variant) in variants.iter().enumerate() {
        let is_last = i == variants.len() - 1;
        let connector = if is_last { "└─ " } else { "├─ " };
        let child_prefix = if is_last { "   " } else { "│  " };

        // Case 1: Simple string const — e.g. {"type": "string", "const": "medoid"}
        if let Some(Value::String(name)) = variant.get("const") {
            let desc = variant.get("description").and_then(Value::as_str);
            write_variant_header(buf, depth, connector, name, desc);
            continue;
        }

        // Case 2: Internally-tagged enum with $ref — variant has both $ref and inline
        // properties containing the tag.
        if variant.get("$ref").is_some() {
            if let Some(inline_props) = variant.get("properties").and_then(Value::as_object) {
                let tag = inline_props
                    .values()
                    .find_map(extract_tag_value);

                if let Some(tag) = tag {
                    let resolved = resolve(variant, defs);
                    let desc = resolved.get("description").and_then(Value::as_str);
                    write_variant_header(buf, depth, connector, &tag, desc);

                    if let Some(ref_props) =
                        resolved.get("properties").and_then(Value::as_object)
                    {
                        let entries: Vec<_> = ref_props.iter().collect();
                        render_field_list(&entries, resolved, defs, buf, depth, child_prefix);
                    }
                    continue;
                }
            }
        }

        let resolved = resolve(variant, defs);

        // Case 3: Internally-tagged enum (has a const/enum in one of the properties).
        if let Some((tag, tag_key)) = detect_tag(resolved) {
            let desc = resolved.get("description").and_then(Value::as_str);
            write_variant_header(buf, depth, connector, &tag, desc);

            if let Some(properties) = resolved.get("properties").and_then(Value::as_object) {
                let content_props: Vec<_> = properties
                    .iter()
                    .filter(|(k, _)| k.as_str() != tag_key)
                    .collect();
                render_field_list(&content_props, resolved, defs, buf, depth, child_prefix);
            }
            continue;
        }

        // Case 4: Externally-tagged enum — single-property wrapper object.
        if let Some(properties) = resolved.get("properties").and_then(Value::as_object) {
            if let Some((variant_name, inner_schema)) = properties.iter().next() {
                if properties.len() == 1 {
                    let inner = resolve(inner_schema, defs);
                    let desc = inner.get("description").and_then(Value::as_str);
                    write_variant_header(buf, depth, connector, variant_name, desc);

                    if let Some(inner_props) =
                        inner.get("properties").and_then(Value::as_object)
                    {
                        let entries: Vec<_> = inner_props.iter().collect();
                        render_field_list(&entries, inner, defs, buf, depth, child_prefix);
                    }
                    continue;
                }
            }
        }

        // Fallback: show type summary.
        let summary = type_summary(resolved);
        write_indented(
            buf,
            depth,
            &format!("{}{}", connector.dimmed(), summary.cyan()),
        );
    }
}

/// Render a list of (name, schema) pairs as indented child fields under a variant.
fn render_field_list(
    entries: &[(&String, &Value)],
    parent: &Value,
    defs: Option<&Value>,
    buf: &mut String,
    depth: usize,
    prefix: &str,
) {
    let required = required_fields(parent);
    let indent = "    ".repeat(depth);

    for (i, (name, schema)) in entries.iter().enumerate() {
        let is_last_field = i == entries.len() - 1;
        let field_connector = if is_last_field { "└── " } else { "├── " };
        let optional_str = if !required.contains(&name.as_str()) {
            format!(" {}", "(optional)".dimmed())
        } else {
            String::new()
        };

        let resolved = resolve(schema, defs);
        let summary = type_summary(resolved);
        let _ = writeln!(
            buf,
            "{indent}{}{}{}: {}{}",
            prefix.dimmed(),
            field_connector.dimmed(),
            name.bold(),
            summary.cyan(),
            optional_str
        );
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Array rendering
// ─────────────────────────────────────────────────────────────────────────────

fn render_array(
    items: &Value,
    _parent: &Value,
    defs: Option<&Value>,
    buf: &mut String,
    depth: usize,
) {
    let resolved = resolve(items, defs);
    let item_summary = type_summary(resolved);
    write_indented(buf, depth, &format!("{}", format!("array of {item_summary}").cyan()));
}

// ─────────────────────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────────────────────

/// Resolve a `$ref` to its target in `$defs`/`definitions`. Returns the node unchanged
/// if it's not a reference.
fn resolve<'a>(node: &'a Value, defs: Option<&'a Value>) -> &'a Value {
    if let Some(ref_str) = node.get("$ref").and_then(Value::as_str) {
        let name = ref_str
            .strip_prefix("#/$defs/")
            .or_else(|| ref_str.strip_prefix("#/definitions/"));

        if let (Some(name), Some(defs)) = (name, defs) {
            if let Some(target) = defs.get(name) {
                return target;
            }
        }
    }
    node
}

/// Produce a short type summary string for a schema node.
fn type_summary(node: &Value) -> String {
    // Check for enum values first.
    if let Some(enum_values) = node.get("enum").and_then(Value::as_array) {
        let formatted: Vec<String> = enum_values
            .iter()
            .map(|v| match v {
                Value::String(s) => format!("\"{s}\""),
                Value::Null => "null".to_string(),
                other => other.to_string(),
            })
            .collect();
        return format!("one of [{}]", formatted.join(", "));
    }

    // Check for const value.
    if let Some(c) = node.get("const") {
        match c {
            Value::String(s) => return format!("\"{s}\""),
            other => return other.to_string(),
        }
    }

    let type_val = node.get("type");

    match type_val.and_then(Value::as_str) {
        Some("string") => {
            if let Some(fmt) = node.get("format").and_then(Value::as_str) {
                format!("string ({fmt})")
            } else {
                "string".to_string()
            }
        }
        Some("integer") => {
            let mut s = "integer".to_string();
            if let Some(min) = node.get("minimum") {
                let _ = write!(s, " (≥{min})");
            } else if let Some(emin) = node.get("exclusiveMinimum") {
                let _ = write!(s, " (>{emin})");
            }
            if let Some(max) = node.get("maximum") {
                let _ = write!(s, " (≤{max})");
            }
            s
        }
        Some("number") => "number".to_string(),
        Some("boolean") => "boolean".to_string(),
        Some("null") => "null".to_string(),
        Some("array") => {
            if let Some(items) = node.get("items") {
                let inner = type_summary(items);
                format!("array of {inner}")
            } else {
                "array".to_string()
            }
        }
        Some("object") => "object".to_string(),
        _ => {
            // Could be oneOf/anyOf at leaf level, or unknown.
            if node.get("oneOf").is_some() || node.get("anyOf").is_some() {
                "(union)".to_string()
            } else {
                "any".to_string()
            }
        }
    }
}

/// A brief hint for complex types used inline (e.g., "object" or "(one of)").
fn brief_type_hint(node: &Value) -> &'static str {
    if node.get("oneOf").is_some() {
        "(one of)"
    } else if node.get("anyOf").is_some() {
        "(any of)"
    } else if node.get("properties").is_some() {
        "object"
    } else {
        ""
    }
}

/// Extract the required field names from a schema node.
fn required_fields(node: &Value) -> Vec<&str> {
    node.get("required")
        .and_then(Value::as_array)
        .map(|arr| arr.iter().filter_map(Value::as_str).collect())
        .unwrap_or_default()
}

/// Extract a tag value from a single property schema.
///
/// Recognizes both `{"const": "value"}` and `{"enum": ["value"]}` patterns.
fn extract_tag_value(prop: &Value) -> Option<String> {
    if let Some(Value::String(v)) = prop.get("const") {
        return Some(v.clone());
    }
    if let Some(arr) = prop.get("enum").and_then(Value::as_array) {
        if arr.len() == 1 {
            if let Some(Value::String(v)) = arr.first() {
                return Some(v.clone());
            }
        }
    }
    None
}

/// Detect the tag field in an internally-tagged enum variant.
///
/// Returns `(tag_value, tag_key)` — the variant name and which property key holds the tag.
fn detect_tag(variant_schema: &Value) -> Option<(String, &str)> {
    let properties = variant_schema.get("properties")?.as_object()?;
    for (key, prop_schema) in properties {
        if let Some(tag) = extract_tag_value(prop_schema) {
            return Some((tag, key.as_str()));
        }
    }
    None
}

/// Write a variant header line: `connector "name" — description`.
fn write_variant_header(
    buf: &mut String,
    depth: usize,
    connector: &str,
    name: &str,
    desc: Option<&str>,
) {
    let desc_str = match desc {
        Some(d) => format!(" — {}", d.dimmed()),
        None => String::new(),
    };
    write_indented(
        buf,
        depth,
        &format!(
            "{}{}{}",
            connector.dimmed(),
            format!("\"{name}\"").yellow(),
            desc_str
        ),
    );
}

/// Write a description, properly handling multi-line text by aligning continuation
/// lines with the first line's `# ` prefix.
fn write_description(buf: &mut String, depth: usize, cont_prefix: &str, desc: &str) {
    let indent = "    ".repeat(depth);
    let lines: Vec<&str> = desc.lines().collect();

    // Only print the first paragraph (up to first blank line) to keep output concise.
    let first_paragraph: Vec<&str> = lines
        .iter()
        .take_while(|line| !line.trim().is_empty())
        .copied()
        .collect();

    let lines_to_print = if first_paragraph.is_empty() {
        &lines[..lines.len().min(1)]
    } else {
        &first_paragraph
    };

    for (i, line) in lines_to_print.iter().enumerate() {
        let trimmed = line.trim();
        if i == 0 {
            let _ = writeln!(buf, "{indent}{}{}", cont_prefix.dimmed(), format!("# {trimmed}").green());
        } else {
            // Continuation lines: align with the text after "# "
            let _ = writeln!(buf, "{indent}{}{}  {}", cont_prefix.dimmed(), "#".green(), trimmed.green());
        }
    }
}

/// Write a line to the buffer with indentation.
fn write_indented(buf: &mut String, depth: usize, text: &str) {
    let indent = "    ".repeat(depth);
    let _ = writeln!(buf, "{indent}{text}");
}

#[cfg(test)]
mod tests {
    use super::*;
    use schemars::JsonSchema;

    fn render_to_string<T: JsonSchema>() -> String {
        let generator = schemars::generate::SchemaSettings::default().into_generator();
        let schema = generator.into_root_schema_for::<T>();
        let value = serde_json::to_value(&schema).unwrap();
        let mut output = Vec::new();
        render(&value, &mut output).unwrap();
        String::from_utf8(output).unwrap()
    }

    #[test]
    fn renders_simple_object() {
        /// A person record.
        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Person {
            /// The name of the person.
            name: String,
            /// Age in years.
            age: u32,
        }

        let text = render_to_string::<Person>();
        assert!(text.contains("name: string"), "got: {text}");
        assert!(text.contains("# The name of the person."), "got: {text}");
        assert!(text.contains("age:"), "got: {text}");
    }

    #[test]
    fn renders_optional_fields() {
        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Config {
            required_field: String,
            optional_field: Option<u32>,
        }

        let text = render_to_string::<Config>();
        // required_field should NOT be marked optional
        assert!(!text.contains("required_field: string (optional)"), "got: {text}");
        assert!(text.contains("(optional)"), "got: {text}");
    }

    #[test]
    fn renders_string_enum() {
        /// Distance metric to use.
        #[derive(JsonSchema)]
        #[serde(rename_all = "snake_case")]
        #[allow(dead_code)]
        enum Metric {
            SquaredL2,
            InnerProduct,
            Cosine,
        }

        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Input {
            metric: Metric,
        }

        let text = render_to_string::<Input>();
        assert!(text.contains("metric:"), "got: {text}");
    }

    #[test]
    fn renders_tagged_enum_variants() {
        /// Strategy for selecting start points.
        #[derive(JsonSchema)]
        #[serde(tag = "method", rename_all = "snake_case")]
        #[allow(dead_code)]
        enum Strategy {
            /// Use the medoid.
            Medoid,
            /// Use random vectors with given parameters.
            RandomVectors {
                norm: f32,
                nsamples: u32,
                seed: u64,
            },
        }

        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Input {
            strategy: Strategy,
        }

        let text = render_to_string::<Input>();
        assert!(text.contains("medoid"), "got: {text}");
        assert!(text.contains("random_vectors"), "got: {text}");
        assert!(text.contains("norm"), "got: {text}");
        assert!(text.contains("nsamples"), "got: {text}");
    }

    #[test]
    fn renders_nullable_field() {
        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Config {
            /// Optional label for the run.
            label: Option<String>,
            name: String,
        }

        let text = render_to_string::<Config>();
        assert!(text.contains("label"), "got: {text}");
        assert!(text.contains("name: string"), "got: {text}");
    }

    #[test]
    fn renders_nested_optional_enum() {
        #[derive(JsonSchema)]
        #[serde(tag = "method", rename_all = "snake_case")]
        #[allow(dead_code)]
        enum Quantization {
            Pq { num_chunks: u32 },
            Sq { bits: u32 },
        }

        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Input {
            /// Optional quantization method.
            quantized: Option<Quantization>,
            data: String,
        }

        let text = render_to_string::<Input>();
        assert!(text.contains("pq"), "got: {text}");
        assert!(text.contains("sq"), "got: {text}");
        assert!(text.contains("data: string"), "got: {text}");
    }

    #[test]
    fn renders_vec_field() {
        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Config {
            /// List of L values to sweep.
            search_l: Vec<u32>,
        }

        let text = render_to_string::<Config>();
        assert!(text.contains("search_l:"), "got: {text}");
        assert!(text.contains("array"), "got: {text}");
    }

    #[test]
    fn renders_tagged_newtype_variants() {
        #[derive(JsonSchema, serde::Serialize, serde::Deserialize)]
        struct TopkPhase {
            queries: String,
            reps: u32,
        }

        #[derive(JsonSchema, serde::Serialize, serde::Deserialize)]
        struct RangePhase {
            radius: f32,
        }

        #[derive(JsonSchema, serde::Serialize, serde::Deserialize)]
        #[serde(tag = "search-type", rename_all = "kebab-case")]
        enum SearchPhase {
            Topk(TopkPhase),
            Range(RangePhase),
        }

        let generator = schemars::generate::SchemaSettings::default().into_generator();
        let schema = generator.into_root_schema_for::<SearchPhase>();
        let value = serde_json::to_value(&schema).unwrap();

        let mut output = Vec::new();
        render(&value, &mut output).unwrap();
        let text = String::from_utf8(output).unwrap();

        assert!(text.contains("topk"), "got: {text}");
        assert!(text.contains("range"), "got: {text}");
        assert!(text.contains("queries"), "got: {text}");
        assert!(text.contains("radius"), "got: {text}");
    }

    #[test]
    fn resolve_path_drills_into_fields() {
        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Inner {
            seed: u64,
            count: u32,
        }

        #[derive(JsonSchema)]
        #[allow(dead_code)]
        struct Outer {
            name: String,
            build: Inner,
        }

        let generator = schemars::generate::SchemaSettings::default().into_generator();
        let schema = generator.into_root_schema_for::<Outer>();
        let value = serde_json::to_value(&schema).unwrap();

        // Single level
        let sub = resolve_path(&value, "build").expect("should resolve 'build'");
        assert!(sub.get("properties").is_some(), "got: {sub}");

        // Nested path
        let sub = resolve_path(&value, "build.seed").expect("should resolve 'build.seed'");
        assert_eq!(
            sub.get("type").and_then(Value::as_str),
            Some("integer"),
            "got: {sub}"
        );

        // Non-existent path
        assert!(resolve_path(&value, "nonexistent").is_none());
        assert!(resolve_path(&value, "build.nonexistent").is_none());
    }
}
